import{c as s,Q as n,j as p,m as e}from"./chunks/framework.CBiVa4O3.js";const u=JSON.parse('{"title":"Uptime 与 Downtime:99%、99.9%、99.99% 到底差多少","description":"","frontmatter":{},"headers":[],"relativePath":"../cloudBasicsLearning/19-Uptime与Downtime.md","filePath":"../cloudBasicsLearning/19-Uptime与Downtime.md","lastUpdated":1779015580000}'),i={name:"../cloudBasicsLearning/19-Uptime与Downtime.md"};function l(t,a,o,c,h,d){return n(),p("div",null,[...a[0]||(a[0]=[e(`<h1 id="uptime-与-downtime-99-、99-9-、99-99-到底差多少" tabindex="-1">Uptime 与 Downtime:99%、99.9%、99.99% 到底差多少 <a class="header-anchor" href="#uptime-与-downtime-99-、99-9-、99-99-到底差多少" aria-label="Permalink to &quot;Uptime 与 Downtime:99%、99.9%、99.99% 到底差多少&quot;">​</a></h1><blockquote><p>一句话先记住:<strong>Uptime 是服务可用的时间比例,Downtime 是服务不可用的时间;多个 9 看起来只差一点点,换成故障时间差很多</strong>。</p></blockquote><p>很多套餐页会写 99%、99.9%、99.99%,初看都很高。但对线上产品来说,99% 和 99.9% 不是&quot;差 0.9 个百分点&quot;那么简单,它可能是每月 7 小时故障和每月 43 分钟故障的差别。</p><p>更重要的是,用户不关心你写了多少个 9。用户只关心打开页面时能不能用、付款时会不会失败、数据会不会丢、故障时有没有说明。</p><hr><h2 id="一、一句话解释" tabindex="-1">一、一句话解释 <a class="header-anchor" href="#一、一句话解释" aria-label="Permalink to &quot;一、一句话解释&quot;">​</a></h2><h3 id="_1-1-uptime-是-能用-不是-机器开着" tabindex="-1">1.1 Uptime 是&quot;能用&quot;,不是&quot;机器开着&quot; <a class="header-anchor" href="#_1-1-uptime-是-能用-不是-机器开着" aria-label="Permalink to &quot;1.1 Uptime 是&quot;能用&quot;,不是&quot;机器开着&quot;&quot;">​</a></h3><p>Uptime 常被翻译成可用时间或在线时间。它真正应该关心的是用户视角的&quot;能用&quot;:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>服务器进程还在:</span></span>
<span class="line"><span>  不一定代表可用</span></span>
<span class="line"><span></span></span>
<span class="line"><span>首页能打开:</span></span>
<span class="line"><span>  也不一定代表核心业务可用</span></span>
<span class="line"><span></span></span>
<span class="line"><span>用户能完成关键动作:</span></span>
<span class="line"><span>  更接近真实可用</span></span></code></pre></div><p>例如你的服务器没有宕机,但数据库连接满了,用户无法登录。这时从机器角度看&quot;还活着&quot;,从用户角度看就是不可用。</p><h3 id="_1-2-downtime-是-不可用-但定义要讲清楚" tabindex="-1">1.2 Downtime 是&quot;不可用&quot;,但定义要讲清楚 <a class="header-anchor" href="#_1-2-downtime-是-不可用-但定义要讲清楚" aria-label="Permalink to &quot;1.2 Downtime 是&quot;不可用&quot;,但定义要讲清楚&quot;">​</a></h3><p>Downtime 也不是一个绝对词。不同场景有不同定义:</p><ul><li>全站打不开</li><li>API 返回大量 5xx</li><li>登录服务不可用</li><li>支付回调失败</li><li>图片和文件无法加载</li><li>后台管理无法访问</li><li>某个地域用户访问异常</li></ul><p>所以讨论可用性之前,先要问一句:我们说的不可用,到底是哪个功能、哪个用户群、哪个时间段不可用?</p><hr><h2 id="二、放在系统哪里" tabindex="-1">二、放在系统哪里 <a class="header-anchor" href="#二、放在系统哪里" aria-label="Permalink to &quot;二、放在系统哪里&quot;">​</a></h2><h3 id="_2-1-uptime-应该从用户链路看" tabindex="-1">2.1 Uptime 应该从用户链路看 <a class="header-anchor" href="#_2-1-uptime-应该从用户链路看" aria-label="Permalink to &quot;2.1 Uptime 应该从用户链路看&quot;">​</a></h3><p>一个典型小网站的访问链路可能是:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户浏览器</span></span>
<span class="line"><span>  -&gt; DNS</span></span>
<span class="line"><span>  -&gt; CDN / WAF</span></span>
<span class="line"><span>  -&gt; 前端托管</span></span>
<span class="line"><span>  -&gt; API 服务</span></span>
<span class="line"><span>  -&gt; 数据库</span></span>
<span class="line"><span>  -&gt; 对象存储</span></span>
<span class="line"><span>  -&gt; 第三方服务</span></span></code></pre></div><p>任意一层出问题,都可能造成 Downtime。常见例子:</p><ul><li>DNS 配错,用户根本找不到网站</li><li>CDN 回源失败,页面间歇性 502</li><li>前端部署坏了,首页白屏</li><li>API 超时,页面能打开但无法保存</li><li>数据库维护,登录和下单失败</li><li>对象存储权限改错,图片全部 403</li><li>第三方支付挂了,订单无法完成</li></ul><p>所以 Uptime 不是某一台机器的指标,而是整条业务链路的结果。</p><h3 id="_2-2-状态页的-uptime-不等于你的-uptime" tabindex="-1">2.2 状态页的 Uptime 不等于你的 Uptime <a class="header-anchor" href="#_2-2-状态页的-uptime-不等于你的-uptime" aria-label="Permalink to &quot;2.2 状态页的 Uptime 不等于你的 Uptime&quot;">​</a></h3><p>云厂商状态页显示&quot;全部正常&quot;,不代表你的应用正常。原因很简单:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>厂商状态页:</span></span>
<span class="line"><span>  统计的是厂商服务整体健康状况</span></span>
<span class="line"><span></span></span>
<span class="line"><span>你的应用:</span></span>
<span class="line"><span>  还包含你的配置、代码、账户额度、权限、部署流程、第三方依赖</span></span></code></pre></div><p>例如对象存储服务整体正常,但你的 Bucket 权限被改错了,用户仍然看不到图片。这个 Downtime 属于你的系统问题,不是云厂商整体故障。</p><h3 id="_2-3-可用性要按核心路径分层" tabindex="-1">2.3 可用性要按核心路径分层 <a class="header-anchor" href="#_2-3-可用性要按核心路径分层" aria-label="Permalink to &quot;2.3 可用性要按核心路径分层&quot;">​</a></h3><p>小团队不需要一开始把所有功能都做成同样可用。更合理的是分层:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>第一层:必须可用</span></span>
<span class="line"><span>  首页、登录、注册、付款、核心 API</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第二层:尽量可用</span></span>
<span class="line"><span>  搜索、评论、通知、文件预览</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第三层:可以延迟</span></span>
<span class="line"><span>  数据导出、报表生成、邮件批量发送、后台统计</span></span></code></pre></div><p>这样故障发生时,你知道优先恢复什么,也知道哪些功能可以临时降级。</p><hr><h2 id="三、常见套餐和使用限制" tabindex="-1">三、常见套餐和使用限制 <a class="header-anchor" href="#三、常见套餐和使用限制" aria-label="Permalink to &quot;三、常见套餐和使用限制&quot;">​</a></h2><h3 id="_3-1-几个-9-换成时间更容易理解" tabindex="-1">3.1 几个 9 换成时间更容易理解 <a class="header-anchor" href="#_3-1-几个-9-换成时间更容易理解" aria-label="Permalink to &quot;3.1 几个 9 换成时间更容易理解&quot;">​</a></h3><p>粗略按 30 天一个月计算:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>99%      每月大约 7.2 小时不可用</span></span>
<span class="line"><span>99.5%    每月大约 3.6 小时不可用</span></span>
<span class="line"><span>99.9%    每月大约 43 分钟不可用</span></span>
<span class="line"><span>99.95%   每月大约 22 分钟不可用</span></span>
<span class="line"><span>99.99%   每月大约 4 分钟不可用</span></span>
<span class="line"><span>99.999%  每月大约 26 秒不可用</span></span></code></pre></div><p>按一年粗略理解:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>99%      每年大约 3.65 天不可用</span></span>
<span class="line"><span>99.9%    每年大约 8.8 小时不可用</span></span>
<span class="line"><span>99.99%   每年大约 53 分钟不可用</span></span>
<span class="line"><span>99.999%  每年大约 5 分钟不可用</span></span></code></pre></div><p>这张表的目的不是让你精算,而是让你看到:从 99.9% 到 99.99%,不是文案上多一个 9,而是工程要求明显上升。</p><h3 id="_3-2-免费套餐常见边界" tabindex="-1">3.2 免费套餐常见边界 <a class="header-anchor" href="#_3-2-免费套餐常见边界" aria-label="Permalink to &quot;3.2 免费套餐常见边界&quot;">​</a></h3><p>免费套餐或低价套餐通常可能有这些限制:</p><ul><li>没有正式 SLA</li><li>只提供社区支持或邮件支持</li><li>故障时不保证响应时间</li><li>日志保留时间短</li><li>监控粒度粗</li><li>不支持多区域部署</li><li>不支持自动故障切换</li><li>超过额度后限流、暂停或计费</li></ul><p>这些限制会直接影响 Downtime。比如没有足够日志,故障时你不知道哪里坏了;没有多区域,单区域故障时只能等恢复;没有预算告警,超额后服务可能被暂停。</p><h3 id="_3-3-计划维护不一定算-downtime" tabindex="-1">3.3 计划维护不一定算 Downtime <a class="header-anchor" href="#_3-3-计划维护不一定算-downtime" aria-label="Permalink to &quot;3.3 计划维护不一定算 Downtime&quot;">​</a></h3><p>很多服务条款会把计划维护排除在 SLA 之外。也就是说:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>厂商提前公告:</span></span>
<span class="line"><span>  某天凌晨维护数据库 30 分钟</span></span>
<span class="line"><span></span></span>
<span class="line"><span>你的用户体验:</span></span>
<span class="line"><span>  这 30 分钟可能确实不能用</span></span>
<span class="line"><span></span></span>
<span class="line"><span>SLA 统计:</span></span>
<span class="line"><span>  可能不算厂商违约</span></span></code></pre></div><p>对用户来说,打不开就是打不开。对合同来说,可能不算赔偿范围。小团队需要理解这两个口径的差别。</p><h3 id="_3-4-局部故障也会影响真实体验" tabindex="-1">3.4 局部故障也会影响真实体验 <a class="header-anchor" href="#_3-4-局部故障也会影响真实体验" aria-label="Permalink to &quot;3.4 局部故障也会影响真实体验&quot;">​</a></h3><p>有些 Downtime 不是全站挂掉,而是局部异常:</p><ul><li>某个国家或地区访问慢</li><li>某个 CDN 节点出错</li><li>某个 API 路由失败</li><li>某类文件无法下载</li><li>移动端正常,桌面端白屏</li><li>新用户不能注册,老用户还能访问</li></ul><p>如果你只监控&quot;首页返回 200&quot;,这些问题可能很晚才发现。</p><hr><h2 id="四、小团队建议" tabindex="-1">四、小团队建议 <a class="header-anchor" href="#四、小团队建议" aria-label="Permalink to &quot;四、小团队建议&quot;">​</a></h2><h3 id="_4-1-先定义-什么叫可用" tabindex="-1">4.1 先定义&quot;什么叫可用&quot; <a class="header-anchor" href="#_4-1-先定义-什么叫可用" aria-label="Permalink to &quot;4.1 先定义&quot;什么叫可用&quot;&quot;">​</a></h3><p>不要一上来就问&quot;我们要几个 9&quot;。先写清楚:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>对这个产品来说:</span></span>
<span class="line"><span>  用户能打开首页算不算可用?</span></span>
<span class="line"><span>  用户能登录但不能付款算不算可用?</span></span>
<span class="line"><span>  管理后台挂了算不算严重事故?</span></span>
<span class="line"><span>  报表晚 1 小时生成算不算不可用?</span></span>
<span class="line"><span>  某个地区访问慢是否算不可用?</span></span></code></pre></div><p>定义清楚以后,再设置监控和目标。否则 Uptime 只是一个漂亮数字。</p><h3 id="_4-2-对早期产品-99-9-通常比-99-99-更现实" tabindex="-1">4.2 对早期产品,99.9% 通常比 99.99% 更现实 <a class="header-anchor" href="#_4-2-对早期产品-99-9-通常比-99-99-更现实" aria-label="Permalink to &quot;4.2 对早期产品,99.9% 通常比 99.99% 更现实&quot;">​</a></h3><p>99.99% 往往意味着:</p><ul><li>更可靠的基础设施</li><li>更好的监控和告警</li><li>更快的故障响应</li><li>更成熟的发布和回滚</li><li>更少的单点依赖</li><li>更高的人力和云资源成本</li></ul><p>如果你的产品还在验证阶段,用户规模不大,没有强合同承诺,盲目追求 99.99% 可能不划算。更实际的目标是:核心路径足够稳定,故障能快速发现,恢复流程不靠临场发挥。</p><h3 id="_4-3-把故障时间分成三段看" tabindex="-1">4.3 把故障时间分成三段看 <a class="header-anchor" href="#_4-3-把故障时间分成三段看" aria-label="Permalink to &quot;4.3 把故障时间分成三段看&quot;">​</a></h3><p>小团队排查 Downtime 时,可以把故障拆成:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>发现时间:</span></span>
<span class="line"><span>  从故障发生到你知道它发生</span></span>
<span class="line"><span></span></span>
<span class="line"><span>定位时间:</span></span>
<span class="line"><span>  从知道故障到找到原因</span></span>
<span class="line"><span></span></span>
<span class="line"><span>恢复时间:</span></span>
<span class="line"><span>  从找到原因到用户恢复可用</span></span></code></pre></div><p>很多团队真正的问题不是恢复很慢,而是发现太晚。用户已经抱怨半小时,团队才知道服务挂了。监控和告警能优先缩短这段时间。</p><h3 id="_4-4-最小可行做法" tabindex="-1">4.4 最小可行做法 <a class="header-anchor" href="#_4-4-最小可行做法" aria-label="Permalink to &quot;4.4 最小可行做法&quot;">​</a></h3><p>一个小产品至少应该有:</p><ul><li>外部可用性探测,从用户视角访问首页和核心接口</li><li>错误率监控,知道 5xx 是否突然升高</li><li>延迟监控,知道服务是否变慢</li><li>数据库连接和容量监控</li><li>部署失败和构建失败通知</li><li>简单状态页或公告渠道</li><li>预算告警,避免欠费或超额导致停机</li></ul><p>这些比一开始做复杂高可用更重要。</p><hr><h2 id="五、一句话总结" tabindex="-1">五、一句话总结 <a class="header-anchor" href="#五、一句话总结" aria-label="Permalink to &quot;五、一句话总结&quot;">​</a></h2><p><strong>Uptime 和 Downtime 要从用户能不能完成核心动作来理解;几个 9 是结果,不是护身符,小团队先定义可用性、监控核心路径、缩短发现和恢复时间。</strong></p>`,71)])])}const m=s(i,[["render",l]]);export{u as __pageData,m as default};
